const {spawn} = require('child_process');
const {mkdtempSync} = require('fs');
const {tmpdir} = require('os');
const {join} = require('path');
const home = mkdtempSync(join(tmpdir(), 'codex-mem-repro-'));
const child = spawn(process.execPath, ['dist/cli.js', 'mcp-server'], {stdio: ['pipe','pipe','pipe'], env: {...process.env, HOME: home}});
const started = Date.now();
setTimeout(() => child.stdin.end(), 500);
child.on('exit', (code, signal) => {
  console.log(JSON.stringify({scenario:'stdin-close', code, signal, elapsed_ms: Date.now()-started}));
  process.exit([0,1].includes(code) ? 0 : 3);
});
setTimeout(() => {
  try { child.kill('SIGKILL'); } catch {}
  console.log(JSON.stringify({scenario:'stdin-close', timeout:true, elapsed_ms: Date.now()-started}));
  process.exit(2);
}, 7000);
